function Invoke-GitChecked {
  & git @args
  if ($LASTEXITCODE -ne 0) { throw "git $($args -join ' ') failed" }
}

function Test-GitDirty {
  $dirty = & git status --porcelain
  if ($LASTEXITCODE -ne 0) { throw "git status failed" }
  if ($null -eq $dirty) { return $false }
  return @($dirty).Count -gt 0
}

function Test-GitLocalBranch {
  param([string]$Branch)

  & git show-ref --verify --quiet "refs/heads/$Branch" *> $null
  if ($LASTEXITCODE -eq 0) { return $true }
  if ($LASTEXITCODE -eq 1) { return $false }
  throw "git show-ref failed"
}

function New-GitWorkBranchName {
  param([string]$Prefix)

  $stamp = Get-Date -Format "yyyyMMdd-HHmmss"
  $candidate = "$Prefix-$stamp"
  $counter = 1
  while (Test-GitLocalBranch -Branch $candidate) {
    $candidate = "$Prefix-$stamp-$counter"
    $counter += 1
  }
  return $candidate
}

function Update-GitMain {
  param([string]$RemoteName, [string]$MainBranch)

  & git fetch $RemoteName $MainBranch
  if ($LASTEXITCODE -ne 0) { throw "Could not fetch $RemoteName/$MainBranch." }
  & git show-ref --verify --quiet "refs/remotes/$RemoteName/$MainBranch" *> $null
  if ($LASTEXITCODE -ne 0) { throw "Remote $RemoteName/$MainBranch was not found." }
  Invoke-GitChecked switch $MainBranch
  & git merge --ff-only "$RemoteName/$MainBranch"
  if ($LASTEXITCODE -ne 0) {
    throw "main cannot be fast-forwarded from $RemoteName/$MainBranch. Resolve main manually, then retry."
  }
}

function Invoke-GitYoloPush {
  param([string]$Branch, [string]$RemoteName, [string]$MainBranch)

  if ($Branch -eq $MainBranch) {
    & git push $RemoteName $MainBranch
    if ($LASTEXITCODE -ne 0) {
      throw "Main push was rejected. Fetch and inspect before retrying; not force-pushing main."
    }
    return
  }

  $upstream = & git rev-parse --abbrev-ref --symbolic-full-name '@{u}' 2>$null
  $hasUpstream = $LASTEXITCODE -eq 0 -and -not [string]::IsNullOrWhiteSpace($upstream)

  if ($hasUpstream) {
    & git push
    if ($LASTEXITCODE -ne 0) {
      Write-Host "Normal push was rejected; retrying with --force-with-lease."
      Invoke-GitChecked push --force-with-lease
    }
  } else {
    & git push --set-upstream $RemoteName $Branch
    if ($LASTEXITCODE -ne 0) {
      Write-Host "Normal upstream push was rejected; retrying with --force-with-lease."
      Invoke-GitChecked push --set-upstream --force-with-lease $RemoteName $Branch
    }
  }
}

function Invoke-GitYoloMain {
  $mainBranch = "main"
  $remoteName = "origin"
  $branch = (& git branch --show-current).Trim()
  if ($LASTEXITCODE -ne 0 -or [string]::IsNullOrWhiteSpace($branch)) { throw "Not on a branch." }

  $workBranch = $branch
  $createdFromMain = $false
  if ($branch -eq $mainBranch -and (Test-GitDirty)) {
    $workBranch = New-GitWorkBranchName -Prefix "work/yolo"
    Write-Host "Local changes are on main; moving them to $workBranch before updating main."
    Invoke-GitChecked switch -c $workBranch
    $createdFromMain = $true
  }

  if (Test-GitDirty) {
    Invoke-GitChecked add -A
    $staged = & git diff --cached --name-only
    if ($LASTEXITCODE -ne 0) { throw "git diff --cached failed" }
    if ($staged) {
      Invoke-GitChecked commit -m "chore: yolo update"
    }
  }

  if ($createdFromMain) {
    try {
      Update-GitMain -RemoteName $remoteName -MainBranch $mainBranch
    } catch {
      & git switch $workBranch *> $null
      throw
    }
    Invoke-GitChecked switch $workBranch
    try {
      Invoke-GitChecked rebase $mainBranch
    } catch {
      Write-Error "Rebase stopped. Resolve conflicts, then run git rebase --continue or git rebase --abort."
      throw
    }
  } elseif ($branch -eq $mainBranch) {
    Update-GitMain -RemoteName $remoteName -MainBranch $mainBranch
    $workBranch = $mainBranch
  }

  Invoke-GitYoloPush -Branch $workBranch -RemoteName $remoteName -MainBranch $mainBranch
  Invoke-GitChecked status --short
}

Invoke-GitYoloMain
